## 2. C / C++ Glue – `blocksci_stubs.c`

> **Important** – the file must be compiled as C++ (`g++`/`clang++`) because it
> includes BlockSci’s C++ headers.  The `extern "C"` wrappers give the OCaml
> runtime a C‑linkage entry point.

```c
/*----------------------------------------------------------------------
   blocksci_stubs.c –  C/C++ glue for the OCaml BlockSci bindings
   ----------------------------------------------------------------------*/

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <cstddef>
#include <cstdint>
#include <string>
#include <vector>

/* ----------------------------------------------------------------------
   Include the (fictional) BlockSci C++ header that defines the iterator.
   In reality replace this include with the real BlockSci header(s).
   ---------------------------------------------------------------------- */
#include "BlockSci.h"          /* <-- your real BlockSci include here */

/* ----------------------------------------------------------------------
   C++ → C bridge helpers
   ---------------------------------------------------------------------- */
extern "C" {

/* ----------------------------------------------------------------------
   OCaml custom block for the iterator.
   ---------------------------------------------------------------------- */
typedef struct {
  BlockIterator *it;          /* pointer to the native iterator */
} iterator_wrapper;

/* Finaliser – called when the OCaml value is GC’d */
static void iterator_finalize(value v) {
  iterator_wrapper *w = (iterator_wrapper *)Data_custom_val(v);
  if (w->it) {
    delete w->it;
    w->it = nullptr;
  }
}

/* Comparison – not needed, but required by the custom ops struct */
static int iterator_compare(value v1, value v2) {
  iterator_wrapper *w1 = (iterator_wrapper *)Data_custom_val(v1);
  iterator_wrapper *w2 = (iterator_wrapper *)Data_custom_val(v2);
  if (w1->it < w2->it) return -1;
  if (w1->it > w2->it) return 1;
  return 0;
}

/* Hash – simple pointer hash */
static intnat iterator_hash(value v) {
  iterator_wrapper *w = (iterator_wrapper *)Data_custom_val(v);
  return (intnat)w->it;
}

/* Custom ops descriptor */
static struct custom_operations iterator_ops = {
  "Blocksci.iterator",
  iterator_finalize,
  iterator_compare,
  iterator_hash,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default,
  custom_fixed_length_default
};

/* ----------------------------------------------------------------------
   Helper: allocate a fresh OCaml `block` record.
   The OCaml type is defined in blocksci.mli as a 4‑field record.
   ---------------------------------------------------------------------- */
static value caml_make_block(const Block &blk) {
  CAMLparam0();
  CAMLlocal1(res);

  /* 4 fields = height, hash, timestamp, tx_count */
  res = caml_alloc(4, 0);
  Store_field(res, 0, Val_int(blk.height));                     /* int */
  Store_field(res, 1, caml_copy_string(blk.hash.c_str()));     /* string */
  Store_field(res, 2, caml_copy_int64((int64_t)blk.timestamp));/* int64 */
  Store_field(res, 3, Val_int(blk.tx_count));                  /* int */

  CAMLreturn(res);
}

/* ----------------------------------------------------------------------
   caml_blocksci_iterator_create : unit -> iterator
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_iterator_create(value unit) {
  CAMLparam1(unit);
  CAMLlocal1(v);

  iterator_wrapper *w = (iterator_wrapper *)caml_stat_alloc(sizeof(iterator_wrapper));
  w->it = new BlockIterator();            /* <-- construct the native iterator */

  v = caml_alloc_custom(&iterator_ops, sizeof(iterator_wrapper), 0, 1);
  Iterator_wrapper *vp = (iterator_wrapper *)Data_custom_val(v);
  *vp = *w;                /* copy the struct (contains the pointer) */
  caml_stat_free(w);      /* the struct itself is not needed any more */

  CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   caml_blocksci_iterator_reset : iterator -> unit
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_iterator_reset(value v_iter) {
  CAMLparam1(v_iter);
  iterator_wrapper *w = (iterator_wrapper *)Data_custom_val(v_iter);
  if (!w->it) caml_failwith("Blocksci.iterator: already closed");
  w->it->reset();                     /* <-- native reset */
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   caml_blocksci_iterator_next : iterator -> block option
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_iterator_next(value v_iter) {
  CAMLparam1(v_iter);
  CAMLlocal1(res);
  iterator_wrapper *w = (iterator_wrapper *)Data_custom_val(v_iter);
  if (!w->it) caml_failwith("Blocksci.iterator: already closed");

  if (w->it->has_next()) {
    Block blk = w->it->next();               /* <-- fetch next native block */
    value ocaml_blk = caml_make_block(blk);
    res = caml_alloc(1, 0);                  /* Some(blk) */
    Store_field(res, 0, ocaml_blk);
  } else {
    res = caml_alloc(0, 0);                  /* None */
  }

  CAMLreturn(res);
}

/* ----------------------------------------------------------------------
   caml_blocksci_iterator_iter : iterator -> (block -> unit) -> unit
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_iterator_iter(value v_iter, value v_cb) {
  CAMLparam2(v_iter, v_cb);
  iterator_wrapper *w = (iterator_wrapper *)Data_custom_val(v_iter);
  if (!w->it) caml_failwith("Blocksci.iterator: already closed");

  /* The iterator is deliberately *tight*: we do not allocate any
     intermediate OCaml structures except the per‑block record. */
  while (w->it->has_next()) {
    Block blk = w->it->next();          /* native fetch */
    value ocaml_blk = caml_make_block(blk);
    /* Call the OCaml callback.  caml_callback_exn returns the exception
       value (or Val_unit if none). */
    value exn = caml_callback_exn(v_cb, ocaml_blk);
    if (Is_exception_result(exn)) {
      /* Propagate the exception – the iterator is left in a well defined
         state (it has already advanced). */
      caml_raise(exn);
    }
  }
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   caml_blocksci_iterator_iteri : iterator -> (int -> block -> unit) -> unit
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_iterator_iteri(value v_iter, value v_cb) {
  CAMLparam2(v_iter, v_cb);
  iterator_wrapper *w = (iterator_wrapper *)Data_custom_val(v_iter);
  if (!w->it) caml_failwith("Blocksci.iterator: already closed");

  int idx = 0;
  while (w->it->has_next()) {
    Block blk = w->it->next();
    value ocaml_blk = caml_make_block(blk);
    value ocaml_idx = Val_int(idx);
    value args[2] = { ocaml_idx, ocaml_blk };
    value exn = caml_callbackN_exn(v_cb, 2, args);
    if (Is_exception_result(exn)) caml_raise(exn);
    ++idx;
  }
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Optional: a manual “close” (not needed if you rely on finalisation).
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_iterator_close(value v_iter) {
  CAMLparam1(v_iter);
  iterator_wrapper *w = (iterator_wrapper *)Data_custom_val(v_iter);
  if (w->it) {
    delete w->it;
    w->it = nullptr;
  }
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   End of extern "C"
   ---------------------------------------------------------------------- */
} /* extern "C" */
```

### What the stub does

| OCaml function | What the stub does (C++) |
|----------------|--------------------------|
| `create`       | `new BlockIterator()` – allocates the native iterator and wraps it in an OCaml custom block. |
| `reset`        | Calls `BlockIterator::reset()` – cheap rewind. |
| `next`         | Calls `has_next()` / `next()` once, builds an OCaml `block` record and returns `Some blk` or `None`. |
| `iter`         | Tight C++ loop (`while (it->has_next()) …`). For each native `Block` a **single** OCaml record is allocated and the user callback is invoked via `caml_callback_exn`. If the callback raises, the exception bubbles out and the iteration stops. |
| `iteri`        | Same as `iter` but also passes the current index (`int`) to the callback. |
| `close` (optional) | Deletes the native iterator immediately; otherwise the finaliser does it when the OCaml value is GC'd. |

The stub uses the *standard* OCaml custom block machinery, so the iterator value can be stored in data structures, passed around, and automatically reclaimed.

---

## 3. How to compile & link (example)

```bash
# ------------------------------------------------------------
# 1. Put the three files in a directory:
#    blocksci.mli   blocksci.ml   blocksci_stubs.c
#
# 2. Compile the OCaml part (empty .ml is fine – all code is in the stubs)
ocamlopt -c blocksci.mli
ocamlopt -c blocksci.ml

# 3. Compile the C++ stub (needs a C++ compiler and the BlockSci headers)
#    Adjust -I and -L according to where BlockSci is installed.
g++ -std=c++17 -I/path/to/blocksci/include \
    -c blocksci_stubs.c -o blocksci_stubs.o \
    -fPIC -Wall -Wextra

# 4. Build the native library (shared object)
g++ -shared -o libblocksci_stubs.so blocksci_stubs.o \
    -L/path/to/blocksci/lib -lblocksci

# 5. Link everything together
ocamlopt -c -thread -I +threads threads.cma    # if you need threads
ocamlopt -o demo.exe blocksci.cmx blocksci_stubs.o \
    -cclib -L/path/to/blocksci/lib -cclib -lblocksci \
    -cclib -lstdc++

# ------------------------------------------------------------
# Now you can use the library from OCaml:
#
#   let it = Blocksci.create () in
#   Blocksci.iter it (fun blk -> Printf.printf "height=%d hash=%s\n"
#                                   blk.Blocksci.height blk.Blocksci.hash)
#
# The whole walk runs at native C++ speed; the only OCaml allocation per
# block is the `block` record that the callback receives.
```

> **Tip for maximum throughput** – If the per‑block work is *very* cheap
> (e.g. just counting), the `caml_callback_exn` overhead may dominate.  In
> that case you can expose a *batch* API (`iter_batch : iterator -> (block
> array -> unit) -> unit`) that delivers the blocks in chunks (e.g. 1 000
> blocks per callback).  Adding such a function is straightforward: allocate a
> `caml_alloc_tuple` of the desired batch size, fill it, then call the OCaml
> closure once per batch.  The current interface is deliberately simple, but
> the design is extensible.

---

### TL;DR – What the user sees

```ocaml
open Blocksci

let () =
  let it = create () in
  (* Fast walk – the heavy lifting stays in C++ *)
  iter it (fun blk ->
    (* user‑provided hot code *)
    if blk.tx_count > 1000 then
      Printf.printf "Huge block %d (%s) – %d txs\n"
        blk.height blk.hash blk.tx_count
  )
```

All the heavy iteration is performed in the C++ `BlockIterator` loop; the OCaml
callback is called **once per block**, with a freshly allocated record that
holds the fields the user asked for.  The binding follows the same mental model
as Pandas/Polars `DataFrame.iterrows` or `Series.apply`, but it stays within
the OCaml runtime’s expectations and is safe for the GC.
